async def _run(
    self,
    function,
    *args,
    nanny: bool = False,
    workers: list[str] | None = None,
    wait: bool = True,
    on_error: Literal["raise", "return", "ignore"] = "raise",
    **kwargs,
):
    responses = await self.scheduler.broadcast(
        msg=dict(
            op="run",
            function=dumps(function),
            args=dumps(args),
            wait=wait,
            kwargs=dumps(kwargs),
        ),
        workers=workers,
        nanny=nanny,
        on_error="return_pickle",
    )
    results = {}
    for key, resp in responses.items():
        if isinstance(resp, bytes):
            # Pickled RPC exception
            exc = loads(resp)
            assert isinstance(exc, Exception)
        elif resp["status"] == "error":
            # Exception raised by the remote function
            _, exc, tb = clean_exception(**resp)
            exc = exc.with_traceback(tb)
        else:
            assert resp["status"] == "OK"
            results[key] = resp["result"]
            continue

        if on_error == "raise":
            raise exc
        elif on_error == "return":
            results[key] = exc
        elif on_error != "ignore":
            raise ValueError(
                "on_error must be 'raise', 'return', or 'ignore'; "
                f"got {on_error!r}"
            )

    if wait:
        return results

