def __init__(
    self,
    dependency: AnyCallable | type[Any],
    use_cache: bool = False,
    sync_to_thread: bool | None = None,
) -> None:
    """Initialize ``Provide``

    Args:
        dependency: Callable to call or class to instantiate. The result is then injected as a dependency.
        use_cache: Cache the dependency return value. Defaults to False.
        sync_to_thread: Run sync code in an async thread. Defaults to False.
    """
    if not callable(dependency):
        raise ImproperlyConfiguredException("Provider dependency must be a callable value")

    is_class_dependency = isclass(dependency)
    self.has_sync_generator_dependency = isgeneratorfunction(
        dependency if not is_class_dependency else dependency.__call__  # type: ignore[operator]
    )
    self.has_async_generator_dependency = isasyncgenfunction(
        dependency if not is_class_dependency else dependency.__call__  # type: ignore[operator]
    )
    has_generator_dependency = self.has_sync_generator_dependency or self.has_async_generator_dependency

    if has_generator_dependency and use_cache:
        raise ImproperlyConfiguredException(
            "Cannot cache generator dependency, consider using Lifespan Context instead."
        )

    has_sync_callable = is_class_dependency or not is_async_callable(dependency)  # pyright: ignore

    if sync_to_thread is not None:
        if has_generator_dependency:
            warn_sync_to_thread_with_generator(dependency, stacklevel=3)  # type: ignore[arg-type]
        elif not has_sync_callable:
            warn_sync_to_thread_with_async_callable(dependency, stacklevel=3)  # pyright: ignore
    elif has_sync_callable and not has_generator_dependency:
        warn_implicit_sync_to_thread(dependency, stacklevel=3)  # pyright: ignore

    if sync_to_thread and has_sync_callable:
        self.dependency = ensure_async_callable(dependency)  # pyright: ignore
        self.has_sync_callable = False
    else:
        self.dependency = dependency  # pyright: ignore
        self.has_sync_callable = has_sync_callable

    self.sync_to_thread = bool(sync_to_thread)
    self.use_cache = use_cache
    self.value: Any = Empty

def for_constrained_field(self, field: FieldDefinition) -> Schema:
    """Create Schema for Pydantic Constrained fields (created using constr(), conint() and so forth, or by subclassing
    Constrained*)

    Args:
        field: A signature field instance.

    Returns:
        A schema instance.
    """
    kwarg_definition = cast("Union[ParameterKwarg, BodyKwarg]", field.kwarg_definition)
    if any(is_class_and_subclass(field.annotation, t) for t in (int, float, Decimal)):
        return create_numerical_constrained_field_schema(field.annotation, kwarg_definition)
    if any(is_class_and_subclass(field.annotation, t) for t in (str, bytes)):
        return create_string_constrained_field_schema(field.annotation, kwarg_definition)
    if any(is_class_and_subclass(field.annotation, t) for t in (date, datetime)):
        return create_date_constrained_field_schema(field.annotation, kwarg_definition)
    return self.for_collection_constrained_field(field)

def _build_error_message(cls, keys: Sequence[str], exc_msg: str, connection: ASGIConnection) -> ErrorMessage:
    """Build an error message.

    Args:
        keys: A list of keys.
        exc_msg: A message.
        connection: An ASGI connection instance.

    Returns:
        An ErrorMessage
    """

    message: ErrorMessage = {"message": exc_msg.split(" - ")[0]}

    if keys:
        message["key"] = key = ".".join(keys)
        if keys[0].startswith("data"):
            message["key"] = message["key"].replace("data.", "")
            message["source"] = "body"
        elif key in connection.query_params:
            message["source"] = ParamType.QUERY
        elif key in connection.path_params:
            message["source"] = ParamType.PATH

        elif key in cls._fields and isinstance(cls._fields[key].kwarg_definition, ParameterKwarg):
            if cast("ParameterKwarg", cls._fields[key].kwarg_definition).cookie:
                message["source"] = ParamType.COOKIE
            elif cast("ParameterKwarg", cls._fields[key].kwarg_definition).header:
                message["source"] = ParamType.HEADER
            else:
                message["source"] = ParamType.QUERY

    return message

