                    const oauthToken = localStorage.getItem('mcp_oauth_token');
                    if (apiKey) headers['X-API-Key'] = apiKey;
                    else if (oauthToken) headers['Authorization'] = 'Bearer ' + oauthToken;
                    return headers;
